import{_ as o,o as t,c as i,a2 as a}from"./chunks/framework.DtwafDNl.js";const u=JSON.parse('{"title":"Browser Softphone","description":"","frontmatter":{},"headers":[],"relativePath":"features/softphone.md","filePath":"features/softphone.md"}'),n={name:"features/softphone.md"};function l(s,e,r,c,h,d){return t(),i("div",null,[...e[0]||(e[0]=[a('<h1 id="browser-softphone" tabindex="-1">Browser Softphone <a class="header-anchor" href="#browser-softphone" aria-label="Permalink to &quot;Browser Softphone&quot;">​</a></h1><p>The browser softphone is an in-browser SIP softphone built into Callytics. You do not need a separate desktop or mobile app to receive calls from inside the dashboard.</p><p>It uses the operator&#39;s linked SIP extension and connects over WebSocket to the Asterisk WebRTC transport.</p><h2 id="how-to-use-it" tabindex="-1">How to use it <a class="header-anchor" href="#how-to-use-it" aria-label="Permalink to &quot;How to use it&quot;">​</a></h2><ol><li>Click the phone bubble in the bottom-right corner of the dashboard.</li><li>Select the operator you want to use.</li><li>Click <code>Connect</code>.</li><li>Wait until the status changes to <code>Registered</code>.</li></ol><p>Once the status shows <code>Registered</code>, that browser session is available to receive calls for that extension.</p><h2 id="receiving-calls" tabindex="-1">Receiving calls <a class="header-anchor" href="#receiving-calls" aria-label="Permalink to &quot;Receiving calls&quot;">​</a></h2><p>When an incoming call reaches the selected extension:</p><ul><li>The bubble pulses green.</li><li>The softphone panel opens.</li><li><code>Answer</code> and <code>Reject</code> buttons appear.</li></ul><p>If you click <code>Answer</code>, the browser accepts the call and attaches the remote audio stream to the page audio output.</p><h2 id="during-a-call" tabindex="-1">During a call <a class="header-anchor" href="#during-a-call" aria-label="Permalink to &quot;During a call&quot;">​</a></h2><p>While the call is active:</p><ul><li>The call timer counts up from <code>00:00</code>.</li><li><code>Hangup</code> ends the active session.</li><li><code>Mute</code> disables your local microphone until you click <code>Unmute</code>.</li></ul><h2 id="outbound-calling" tabindex="-1">Outbound calling <a class="header-anchor" href="#outbound-calling" aria-label="Permalink to &quot;Outbound calling&quot;">​</a></h2><p>Operators can place outbound calls directly from the softphone bubble.</p><ol><li>Type an extension number or external number into the dial field.</li><li>Click <code>Call</code>.</li><li>While the destination is ringing, the softphone shows <code>Calling...</code> with a <code>Cancel</code> button.</li><li>Once the other side answers, the live call view appears with the timer plus <code>Hangup</code> and <code>Mute</code> controls.</li></ol><h2 id="limitations" tabindex="-1">Limitations <a class="header-anchor" href="#limitations" aria-label="Permalink to &quot;Limitations&quot;">​</a></h2><ul><li>Refreshing the browser disconnects the softphone. After a refresh, click <code>Connect</code> again so the browser re-registers.</li><li>Local development currently expects plain <code>http</code> and <code>ws</code> usage. Production TLS support for secure <code>https</code> and <code>wss</code> WebRTC deployment is a future phase.</li></ul><h2 id="using-it-with-zoiper-or-linphone" tabindex="-1">Using it with Zoiper or Linphone <a class="header-anchor" href="#using-it-with-zoiper-or-linphone" aria-label="Permalink to &quot;Using it with Zoiper or Linphone&quot;">​</a></h2><p>The browser softphone works alongside Zoiper, Linphone, or another SIP client on the same extension credentials.</p><p>Both endpoints can stay registered at the same time, but only one endpoint will ring for a given incoming call. If you need predictable ringing behavior, use separate extensions per device.</p>',21)])])}const b=o(n,[["render",l]]);export{u as __pageData,b as default};
